
"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import {
  Zap, Loader2, Navigation, Timer, Flag, Trophy, MapPin, Star, Clock, Play, Target, X, Gauge, ShieldAlert, Radio, StopCircle, ChevronRight, Waves, Flame, Map, AlertTriangle, Thermometer, Sun
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, where, getCountFromServer } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";
import { RenderCarIcon } from "@/components/icons/car-icons";
import { reverseGeocode } from "@/services/navigation/geocodingService";
import { ManeuverIcon } from "@/components/navigation/maneuver-icon";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 rounded-3xl min-h-[160px]">
      <div className="flex flex-col items-center gap-2">
        <Loader2 className="w-6 h-6 animate-spin text-accent" />
        <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground">Ngarkimi...</span>
      </div>
    </div>
  )
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';
type CockpitMode = 'eco' | 'drag' | 'nav';

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps,
    currentCoords, routePoints, telemetry, startTime, heading,
    runMode, dragTime, isDragFinished, isDragActive, isNavigating, currentStep, currentRoadName, distanceToNextStep, routeData, countdown, isJumpStart,
    setRunMode, startTrip, stopTrip, resetTrip, requestWakeLock, clearNavigation
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [kosovoRank, setKosovoRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  const [hasRankingData, setHasRankingData] = useState(false);
  const [liveDragTimer, setLiveDragTimer] = useState(0);
  
  const requestRef = useRef<number>(undefined);
  const startTimeRef = useRef<number>(undefined);

  const { toast } = useToast();

  const cockpitMode = useMemo((): CockpitMode => {
    if (isNavigating) return 'nav';
    if (runMode !== 'free') return 'drag';
    return 'eco';
  }, [isNavigating, runMode]);

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    const animate = () => {
      if (startTimeRef.current) {
        setLiveDragTimer((performance.now() - startTimeRef.current) / 1000);
      }
      requestRef.current = requestAnimationFrame(animate);
    };

    if (isDragActive) {
      startTimeRef.current = performance.now();
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      startTimeRef.current = undefined;
      setLiveDragTimer(0);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isDragActive]);

  const isWaitingForStart = isDriving && !isDragActive && !isDragFinished && 
    (runMode === '0-60' || runMode === '0-100' || runMode === '1/4mile') && !isJumpStart;

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    try {
      const publicRunsCol = collection(db, "public_runs");
      const runTypeLabel = runMode === 'free' ? 'Top Speed' : runMode;
      const val = (runMode === 'free' || !dragTime) ? peakSpeed : dragTime;

      if (!val || val <= 0) {
        setIsRankingLoading(false);
        return;
      }

      setHasRankingData(true);
      const kosovoQuery = query(publicRunsCol, where("runType", "==", runTypeLabel), runMode === 'free' ? where("peakSpeedKmH", ">", val) : where("dragTime", "<", val));
      const kosovoSnapshot = await getCountFromServer(kosovoQuery);
      setKosovoRank(kosovoSnapshot.data().count + 1);

      if (profile.city) {
        const cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", runTypeLabel), runMode === 'free' ? where("peakSpeedKmH", ">", val) : where("dragTime", "<", val));
        const citySnapshot = await getCountFromServer(cityQuery);
        setCityRank(citySnapshot.data().count + 1);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
      setTimeout(() => stopTrip(), 1000);
    }
  }, [isDragFinished, mounted]);

  const handleStartMission = () => {
    if (runMode !== 'free' && speed > 0) {
      toast({ variant: "destructive", title: "GABIM", description: "Ndalo makinën në 0 km/h për të filluar." });
      return;
    }
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    if (!isJumpStart && (isDragFinished || runMode === 'free')) {
      setShowSummary(true);
      calculateRanks();
    } else {
      resetTrip();
    }
    stopTrip();
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: runMode === 'free' ? 'Top Speed' : runMode,
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      telemetry: telemetry,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };

    addDocumentNonBlocking(collection(db, "users", user.uid, "runs"), runData);
    addDocumentNonBlocking(collection(db, "public_runs"), runData);

    toast({ title: "Ruajtur!", description: "Gara u sinkronizua në Ranking." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
  };

  const rpm = useMemo(() => {
    if (speed === 0) return 800;
    const gear = Math.floor(speed / 60) + 1;
    const speedInGear = speed % 60;
    return Math.min(1200 + (gear * 100) + (speedInGear * 110), 8000);
  }, [speed]);

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) return;
    const { road, city } = await reverseGeocode(currentCoords.lat, currentCoords.lng);
    addDocumentNonBlocking(collection(db, "radar_reports"), {
      type, lat: currentCoords.lat, lng: currentCoords.lng, location: road, city: city,
      createdAt: new Date().toISOString(), userId: user.uid
    });
    toast({ title: "Raportuar!", description: `${type} në ${road}.` });
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  return (
    <div className="flex flex-col min-h-full bg-[#050505] text-white pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      {/* Dynamic Header - Environment Data */}
      <div className="p-6 flex items-center justify-between z-30 apple-slide-up">
        <div className="flex items-center gap-4">
           <div className="flex items-center gap-1.5 bg-white/5 px-3 py-1.5 rounded-full border border-white/10">
             <Thermometer className="w-3 h-3 text-red-500" />
             <span className="text-[10px] font-black tracking-tight">24°C</span>
           </div>
           <div className="flex items-center gap-1.5 bg-white/5 px-3 py-1.5 rounded-full border border-white/10">
             <Sun className="w-3 h-3 text-yellow-500" />
             <span className="text-[10px] font-black tracking-tight">PRISHTINË</span>
           </div>
        </div>
        <div className="flex items-center gap-3">
           <Clock className="w-3.5 h-3.5 text-muted-foreground" />
           <span className="text-xs font-black tabular-nums">{new Date().toLocaleTimeString('sq-AL', { hour: '2-digit', minute: '2-digit' })}</span>
        </div>
      </div>

      {/* Main Cockpit Display */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-4 mt-2">
        
        {/* Transmission & Status Display */}
        <div className="flex gap-6 mb-10 z-20 apple-scale-in">
          {['P', 'R', 'N', 'D'].map((gear) => (
            <span key={gear} className={cn(
              "text-lg font-black italic tracking-tighter transition-all duration-500",
              (speed > 0 && gear === 'D') || (speed === 0 && gear === 'P') 
                ? "text-white scale-125 drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
                : "text-white/10"
            )}>
              {gear}
            </span>
          ))}
        </div>

        {/* Central Instrument Cluster */}
        <div className="relative w-full max-w-[380px] aspect-square flex items-center justify-center apple-scale-in">
          
          {/* Navigation Mini-Map (Left Side) */}
          {isNavigating && routeData && (
            <div className="absolute -left-10 top-1/2 -translate-y-1/2 w-48 h-48 rounded-[2rem] overflow-hidden border border-white/10 shadow-2xl z-10 hidden sm:block">
               <RouteMap points={routeData.coordinates} userLocation={currentCoords} heading={heading} />
               <div className="absolute inset-0 bg-gradient-to-r from-black/20 to-transparent pointer-events-none" />
            </div>
          )}

          {/* Navigation Info (Right Side) */}
          {isNavigating && (
            <div className="absolute -right-10 top-1/2 -translate-y-1/2 w-48 p-4 bg-zinc-900/40 backdrop-blur-xl border border-white/10 rounded-[2rem] z-10 hidden sm:flex flex-col gap-2">
               <div className="w-10 h-10 bg-blue-500/20 rounded-xl flex items-center justify-center border border-blue-500/20">
                 <ManeuverIcon type={currentStep?.type} modifier={currentStep?.modifier} className="w-6 h-6 text-blue-400" />
               </div>
               <div>
                 <p className="text-xl font-black italic text-white leading-none">
                   {distanceToNextStep >= 1000 ? `${(distanceToNextStep / 1000).toFixed(1)}km` : `${distanceToNextStep}m`}
                 </p>
                 <p className="text-[8px] font-black text-white/40 uppercase tracking-widest mt-1 truncate">{currentStep?.instruction || "Vazhdoni drejt"}</p>
               </div>
            </div>
          )}

          {/* Gauge SVG */}
          <svg viewBox="0 0 400 400" className="w-full h-full transform -rotate-90 absolute inset-0 filter drop-shadow-[0_0_20px_rgba(0,0,0,0.8)]">
            {/* Background Glow */}
            <circle cx="200" cy="200" r="180" fill="radial-gradient(circle, rgba(255,0,0,0.05) 0%, transparent 70%)" />
            
            {/* Outer Power Ring (Red) */}
            <circle cx="200" cy="200" r="185" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-white/5" />
            <circle
              cx="200" cy="200" r="185"
              stroke="url(#powerGradient)"
              strokeWidth="6"
              fill="transparent"
              strokeDasharray={2 * Math.PI * 185}
              strokeLinecap="round"
              style={{
                strokeDashoffset: (2 * Math.PI * 185) - (rpm / 8000) * (2 * Math.PI * 185),
                transition: 'stroke-dashoffset 0.1s cubic-bezier(0.2, 0.8, 0.2, 1)'
              }}
              className="drop-shadow-[0_0_8px_rgba(239,68,68,0.4)]"
            />

            {/* Inner Eco/Charge Ring (Cyan) */}
            <circle cx="200" cy="200" r="160" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-white/5" />
            <circle
              cx="200" cy="200" r="160"
              stroke="url(#ecoGradient)"
              strokeWidth="12"
              fill="transparent"
              strokeDasharray={2 * Math.PI * 160}
              strokeLinecap="round"
              style={{
                strokeDashoffset: (2 * Math.PI * 160) - (Math.min(speed, 280) / 280) * (2 * Math.PI * 160),
                transition: 'stroke-dashoffset 0.15s cubic-bezier(0.2, 0.8, 0.2, 1)'
              }}
              className="drop-shadow-[0_0_12px_rgba(6,182,212,0.5)]"
            />

            <defs>
              <linearGradient id="powerGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#7f1d1d" />
                <stop offset="100%" stopColor="#ef4444" />
              </linearGradient>
              <linearGradient id="ecoGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#083344" />
                <stop offset="100%" stopColor="#06b6d4" />
              </linearGradient>
            </defs>
          </svg>

          {/* Speed & Mode Readout */}
          <div className="z-20 flex flex-col items-center">
            <div className="bg-white/5 border border-white/10 px-3 py-1 rounded-md mb-2">
               <span className="text-[10px] font-black text-accent tracking-widest italic">ECO</span>
            </div>
            <div className="flex flex-col items-center">
              <span className={cn(
                "font-black tracking-tighter leading-none tabular-nums text-white transition-all duration-75 text-8xl italic",
                isJumpStart && "text-red-500"
              )}>
                {speed}
              </span>
              <span className="font-black uppercase tracking-[0.4em] text-[10px] text-white/40 mt-2">KM/H</span>
            </div>
          </div>

          {/* Drag Countdown / Signal */}
          {cockpitMode === 'drag' && isWaitingForStart && (
            <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-3 z-30">
              {[1, 2, 3, 4, 5].map((i) => (
                <div key={i} className={cn("w-4 h-4 rounded-full border border-white/10 transition-all duration-300", countdown >= i ? "bg-red-600 shadow-[0_0_15px_rgba(220,38,38,0.8)]" : "bg-zinc-900")} />
              ))}
              <div className={cn("w-6 h-6 rounded-full border border-white/10 transition-all duration-500", countdown >= 6 ? "bg-green-500 shadow-[0_0_20px_rgba(34,197,94,1)] scale-110" : "bg-zinc-900")} />
            </div>
          )}
        </div>

        {/* Dynamic Labels */}
        <div className="w-full max-w-[340px] flex justify-between px-4 mt-4 opacity-40">
           <span className="text-[8px] font-black tracking-widest uppercase">CHARGE%</span>
           <span className="text-[8px] font-black tracking-widest uppercase">POWER%</span>
        </div>

        {/* Quick Reports Bar */}
        <div className="w-full max-w-[320px] grid grid-cols-3 gap-2 mt-8 stagger-1 apple-slide-up">
          <Button onClick={() => handleQuickReport('Radar')} className="h-12 bg-white/5 border border-white/5 rounded-2xl flex flex-col gap-0.5 group hover:border-red-500/30">
            <Radio className="w-4 h-4 text-red-500 group-hover:animate-pulse" />
            <span className="text-[8px] font-black uppercase tracking-widest">RADAR</span>
          </Button>
          <Button onClick={() => handleQuickReport('Polici')} className="h-12 bg-white/5 border border-white/5 rounded-2xl flex flex-col gap-0.5 group hover:border-blue-500/30">
            <Radio className="w-4 h-4 text-blue-500" />
            <span className="text-[8px] font-black uppercase tracking-widest">POLICI</span>
          </Button>
          <Button onClick={() => handleQuickReport('Kontrollë')} className="h-12 bg-white/5 border border-white/5 rounded-2xl flex flex-col gap-0.5 group hover:border-zinc-500/30">
            <Radio className="w-4 h-4 text-zinc-400" />
            <span className="text-[8px] font-black uppercase tracking-widest">KONTROLL</span>
          </Button>
        </div>

        {/* Control Button */}
        <div className="w-full max-w-[280px] mt-10 stagger-2 apple-slide-up">
          <Button
            onClick={() => isDriving ? handleStopMission() : handleStartMission()}
            className={cn(
              "w-full h-16 rounded-full font-black text-sm uppercase tracking-widest transition-all shadow-2xl active:scale-95 border-b-4",
              isDriving ? "bg-red-950/40 border-red-500/30 text-white" : "bg-accent border-accent/50 text-background"
            )}
          >
            {isDriving ? "STOP MISSION" : `START ${runMode.toUpperCase()}`}
          </Button>
        </div>
      </div>

      {/* Summary Dialog - Identical Logic */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-[#0c0c0e] border-white/5 w-[94%] max-w-sm rounded-[2.5rem] p-6 apple-scale-in">
          <div className="space-y-6">
            <div className="text-center">
              <h2 className="text-2xl font-black italic tracking-tighter">REZULTATI</h2>
              <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mt-1">
                {runMode === 'free' ? 'Top Speed Session' : `${runMode} Performance`}
              </p>
            </div>

            <div className="bg-zinc-900/50 p-8 rounded-[2rem] border border-white/5 text-center relative overflow-hidden">
              <span className="text-6xl font-black text-white italic">
                {(runMode === 'free' || !dragTime) ? peakSpeed : dragTime?.toFixed(2)}
              </span>
              <span className="text-xl font-black text-white/50 ml-2 italic">
                {(runMode === 'free' || !dragTime) ? 'km/h' : 's'}
              </span>
              
              {isRankingLoading ? (
                <div className="mt-4 flex justify-center"><Loader2 className="w-4 h-4 animate-spin text-accent" /></div>
              ) : (
                <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-black text-accent uppercase tracking-wider">
                  <Trophy className="w-3 h-3" />
                  {cityRank ? `#${cityRank} në ${profile?.city}` : "Rekord i Ri!"}
                </div>
              )}
            </div>

            <div className="flex flex-col gap-2">
              <Button onClick={handleSaveRun} disabled={isSaving} className="w-full h-14 bg-red-600 text-white rounded-[1.5rem] font-black uppercase text-[11px] tracking-widest shadow-xl">
                {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "RUAJ REZULTATIN"}
              </Button>
              <Button variant="ghost" className="w-full h-10 rounded-xl font-black uppercase text-[9px] text-zinc-600" onClick={() => { setShowSummary(false); resetTrip(); }}>
                FSHIJ RRUGËTIMIN
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
}
